// ============================================================
// TOOL: nano_banana_pro - 4K Image Generation
// Google Imagen 3 API - Up to 4096x4096
// ============================================================

const config = $input.json;

// ✅ RÉCUPÉRER LA GOOGLE API KEY DEPUIS LES VARIABLES D'ENVIRONNEMENT
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY;

if (!GOOGLE_API_KEY) {
  return {
    success: false,
    error: 'GOOGLE_API_KEY manquant. Ajoute-la dans Settings > Variables de n8n, puis redémarre n8n.'
  };
}

// Valider les paramètres
if (!config.prompt) {
  return {
    success: false,
    error: "Le paramètre 'prompt' est requis"
  };
}

const {
  prompt,
  resolution = "4096x4096",
  style = "professional_photo",
  quality = "professional",
  negative_prompt = "blurry, low quality, watermark, text, logo",
  creativity = 70,
  guidance_scale = 7.5,
  seed = null
} = config;

try {
  // ✅ APPEL API RÉEL À GOOGLE IMAGEN 3
  const response = await fetch('https://us-central1-aiplatform.googleapis.com/v1/projects/YOUR_PROJECT_ID/locations/us-central1/publishers/google/models/imagegeneration@006:predict', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${GOOGLE_API_KEY}`
    },
    body: JSON.stringify({
      instances: [{
        prompt: prompt,
        negativePrompt: negative_prompt
      }],
      parameters: {
        sampleCount: 1,
        aspectRatio: "1:1",
        safetySetting: "block_some",
        personGeneration: "allow_adult"
      }
    })
  });

  if (!response.ok) {
    const errorData = await response.json();
    return {
      success: false,
      error: `Google API Error: ${response.status}`,
      details: errorData
    };
  }

  const data = await response.json();
  const imageBase64 = data.predictions[0].bytesBase64Encoded;

  return {
    success: true,
    tool: "nano_banana_pro",
    model: "imagen-3",
    output: {
      image_base64: imageBase64,
      format: "png",
      resolution: resolution,
      style: style,
      quality: quality,
      prompt_used: prompt,
      negative_prompt_used: negative_prompt,
      metadata: {
        creativity: creativity,
        guidance_scale: guidance_scale,
        seed: seed,
        generated_at: new Date().toISOString()
      }
    },
    message: "Image 4K générée avec succès"
  };

} catch (error) {
  return {
    success: false,
    tool: "nano_banana_pro",
    error: error.message || "Erreur lors de la génération de l'image",
    details: error.toString()
  };
}

// ============================================================
// TOOL: veo3 - Video Generation
// Google Veo-3 API - Text-to-Video & Image-to-Video
// ============================================================

const config = $input.json;

// ✅ RÉCUPÉRER LA GOOGLE API KEY DEPUIS LES VARIABLES D'ENVIRONNEMENT
const GOOGLE_API_KEY = $env.GOOGLE_API_KEY;

if (!GOOGLE_API_KEY) {
  return {
    success: false,
    error: 'GOOGLE_API_KEY manquant. Ajoute-la dans Settings > Variables de n8n, puis redémarre n8n.'
  };
}

// Valider les paramètres
if (!config.prompt) {
  return {
    success: false,
    error: "Le paramètre 'prompt' est requis"
  };
}

const {
  prompt,
  duration = 8,
  resolution = "1080p",
  fps = 30,
  style = "cinematic",
  camera_motion = "pan",
  aspect_ratio = "16:9",
  extend_from_video = null,
  animate_from_image = null,
  interpolate_to_fps = null
} = config;

// Mapper resolution vers dimensions
const resolutionMap = {
  "720p": { width: 1280, height: 720 },
  "1080p": { width: 1920, height: 1080 }
};

const dimensions = resolutionMap[resolution] || resolutionMap["1080p"];

try {
  // ✅ APPEL API RÉEL À GOOGLE VEO-3 (via Vertex AI)
  const response = await fetch('https://us-central1-aiplatform.googleapis.com/v1/projects/YOUR_PROJECT_ID/locations/us-central1/publishers/google/models/veo-003:predict', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${GOOGLE_API_KEY}`
    },
    body: JSON.stringify({
      instances: [{
        prompt: prompt
      }],
      parameters: {
        durationSeconds: duration,
        width: dimensions.width,
        height: dimensions.height,
        fps: fps,
        aspectRatio: aspect_ratio
      }
    })
  });

  if (!response.ok) {
    const errorData = await response.json();
    return {
      success: false,
      error: `Google API Error: ${response.status}`,
      details: errorData
    };
  }

  const data = await response.json();
  const videoBase64 = data.predictions[0].bytesBase64Encoded;
  const videoUrl = data.predictions[0].videoUri || null;

  return {
    success: true,
    tool: "veo3",
    model: "veo-3",
    output: {
      video_url: videoUrl,
      video_base64: videoBase64,
      format: "mp4",
      duration_seconds: duration,
      resolution: resolution,
      dimensions: dimensions,
      fps: fps,
      style: style,
      camera_motion: camera_motion,
      aspect_ratio: aspect_ratio,
      prompt_used: prompt,
      metadata: {
        generated_at: new Date().toISOString(),
        file_size_estimate_mb: Math.round(duration * 10)
      }
    },
    message: `Vidéo ${duration}s générée avec succès en ${resolution}`
  };

} catch (error) {
  return {
    success: false,
    tool: "veo3",
    error: error.message || "Erreur lors de la génération de la vidéo",
    details: error.toString()
  };
}

// ============================================================
// TOOL: elevenlabs - Voice & Audio Generation
// ElevenLabs API - Text-to-Speech & Sound Effects
// ============================================================

const config = $input.json;

// Déterminer le mode: TTS ou Sound Effects
const mode = config.mode || (config.text ? "tts" : "sound_effects");

if (mode === "tts") {
  // ─────────────────────────────────────────────────────────
  // MODE: TEXT-TO-SPEECH
  // ─────────────────────────────────────────────────────────
  if (!config.text) {
    return {
      success: false,
      error: "Le paramètre 'text' est requis pour le mode TTS"
    };
  }

  const {
    text,
    voice_id = "21m00Tcm4TlvDq8ikWAM", // Default: Rachel (calm, professional female)
    model = "multilingual_v2",
    stability = 0.75,
    similarity_boost = 0.75,
    style = 0.5,
    use_speaker_boost = true,
    language_code = "en"
  } = config;

  try {
    // ✅ RÉCUPÉRER LA ELEVENLABS API KEY
    const ELEVENLABS_API_KEY = $env.ELEVENLABS_API_KEY;

    if (!ELEVENLABS_API_KEY) {
      return {
        success: false,
        error: 'ELEVENLABS_API_KEY manquant. Ajoute-la dans Settings > Variables de n8n, puis redémarre n8n.'
      };
    }

    // ✅ APPEL API RÉEL À ELEVENLABS
    const response = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${voice_id}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'xi-api-key': ELEVENLABS_API_KEY
      },
      body: JSON.stringify({
        text: text,
        model_id: model,
        voice_settings: {
          stability: stability,
          similarity_boost: similarity_boost,
          style: style,
          use_speaker_boost: use_speaker_boost
        }
      })
    });

    if (!response.ok) {
      const errorData = await response.json();
      return {
        success: false,
        error: `ElevenLabs API Error: ${response.status}`,
        details: errorData
      };
    }

    const audioBuffer = await response.arrayBuffer();
    const audioBase64 = Buffer.from(audioBuffer).toString('base64');

    return {
      success: true,
      tool: "elevenlabs",
      mode: "tts",
      output: {
        audio_base64: audioBase64,
        format: "mp3",
        sample_rate: 44100,
        duration_estimate_seconds: Math.ceil(text.length / 15), // ~15 chars/second
        text_used: text,
        voice_id: voice_id,
        model: model,
        language: language_code,
        metadata: {
          stability: stability,
          similarity_boost: similarity_boost,
          style: style,
          generated_at: new Date().toISOString()
        }
      },
      message: "Audio TTS généré avec succès"
    };

  } catch (error) {
    return {
      success: false,
      tool: "elevenlabs",
      mode: "tts",
      error: error.message || "Erreur lors de la génération de l'audio TTS",
      details: error.toString()
    };
  }

} else {
  // ─────────────────────────────────────────────────────────
  // MODE: SOUND EFFECTS
  // ─────────────────────────────────────────────────────────
  if (!config.prompt) {
    return {
      success: false,
      error: "Le paramètre 'prompt' est requis pour le mode sound_effects"
    };
  }

  const {
    prompt,
    duration_seconds = 5,
    prompt_influence = 0.5
  } = config;

  // Valider durée (0.5-22s)
  if (duration_seconds < 0.5 || duration_seconds > 22) {
    return {
      success: false,
      error: "La durée doit être entre 0.5 et 22 secondes"
    };
  }

  try {
    // ✅ RÉCUPÉRER LA ELEVENLABS API KEY
    const ELEVENLABS_API_KEY = $env.ELEVENLABS_API_KEY;

    if (!ELEVENLABS_API_KEY) {
      return {
        success: false,
        error: 'ELEVENLABS_API_KEY manquant. Ajoute-la dans Settings > Variables de n8n, puis redémarre n8n.'
      };
    }

    // ✅ APPEL API RÉEL À ELEVENLABS SOUND GENERATION
    const response = await fetch('https://api.elevenlabs.io/v1/sound-generation', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'xi-api-key': ELEVENLABS_API_KEY
      },
      body: JSON.stringify({
        text: prompt,
        duration_seconds: duration_seconds,
        prompt_influence: prompt_influence
      })
    });

    if (!response.ok) {
      const errorData = await response.json();
      return {
        success: false,
        error: `ElevenLabs API Error: ${response.status}`,
        details: errorData
      };
    }

    const audioBuffer = await response.arrayBuffer();
    const audioBase64 = Buffer.from(audioBuffer).toString('base64');

    return {
      success: true,
      tool: "elevenlabs",
      mode: "sound_effects",
      output: {
        audio_base64: audioBase64,
        format: "mp3",
        sample_rate: 44100,
        duration_seconds: duration_seconds,
        prompt_used: prompt,
        metadata: {
          prompt_influence: prompt_influence,
          generated_at: new Date().toISOString()
        }
      },
      message: `Sound effect ${duration_seconds}s généré avec succès`
    };

  } catch (error) {
    return {
      success: false,
      tool: "elevenlabs",
      mode: "sound_effects",
      error: error.message || "Erreur lors de la génération du sound effect",
      details: error.toString()
    };
  }
}

